#include<bits/stdc++.h>
struct node
{
    int x,y,step;
};
using namespace std;
int mp1[5010][5010];
int dx[4]={0,-1,0,1},dy[4]={1,0,-1,0};
bool vis[5010][5010];
int main()
{
    int n,sx,sy;
    int h=0,w=0;
    scanf("%d%d%d",&n,&sx,&sy);
    for(int i=1;i<=n;i++)
    {
        int a,b;
        scanf("%d%d",&a,&b);
        h=max(h,a);
        w=max(w,b);
        mp1[a][b]=1;
    }
    deque<node> q;
    q.push_back((node){sx,sy,0});
    while(!q.empty())
    {
        auto t=q.front();
        q.pop_front();
        // printf("%d %d %d\n",t.x,t.y,t.step);
        if(t.x==0&&t.y==0)
        {
            printf("%d",t.step);
            return 0;
        }
        for(int i=0;i<4;i++)
        {
            auto t1=(node){t.x+dx[i],t.y+dy[i],t.step};
            if(t1.x<0||t1.x>1001||t1.y<0||t1.y>1001||vis[t1.x][t1.y])
            {
                continue;
            }
            vis[t1.x][t1.y]=1;
            if(mp1[t1.x][t1.y]==1)
            {
                t1.step++;
                q.push_back(t1);
            }
            else
            {
                q.push_front(t1);
            }
        }
    }
    return 0;
}
